#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=10015,inf=0x3f3f3f3f;
int l,s,t,n,a[N],b[N],dp[N],vis[N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>l>>s>>t>>n;
	if(s==t)
	{
		int cnt=0,x;
		for(int i=1;i<=n;i++)
		{
			cin>>x;
			cnt+=(x%s==0);
		}
		cout<<cnt;
		return 0;
	}
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	sort(a+1,a+1+n);
	b[n+1]=min(l-a[n],100);
	l=0;
	for(int i=1;i<=n;i++)
	{
		b[i]=min(a[i]-a[i-1],90);
		l+=b[i];
		vis[l]=1;
	}
	l+=b[n+1];
	for(int i=1;i<=l+9;i++)
	{
		dp[i]=inf;
		for(int j=s;j<=t;j++)
		{
			if(i<j) continue;
			dp[i]=min(dp[i],dp[i-j]+vis[i]);
		}
	}
	int mn=inf;
	for(int i=l;i<=l+9;i++) mn=min(mn,dp[i]);
	cout<<mn;
	return 0;
}
